import React, { useState } from 'react';
import { NavigationDrawer, Button } from '@salutejs/plasma-web';
import { IconBlankOutline, IconSettingsFill, IconHomeAltFill, IconLogout, IconStacksOutline } from '@salutejs/plasma-icons';
export function App() {
    const [isOpen, setIsOpen] = useState(true);
    return (
        <div style={{position: 'relative'}}>
            <NavigationDrawer
                opened={isOpen}
                sections={[
                    {
                        label: 'Основная секция',
                        items: [
                            {
                                label: 'Главная',
                                icon: <IconHomeAltFill />,
                                selected: true,
                                action: () => console.log('Главная')
                            },
                            {
                                label: 'Настройки',
                                icon: <IconSettingsFill />,
                                action: () => console.log('Настройки'),
                            },
                        ]
                    },
                    {
                        label: 'Документы',
                        items: [
                            {
                                label: 'Обзор документов',
                                icon: <IconBlankOutline />,
                                action: () => console.log('Обзор документов'),
                            },
                            {
                                label: 'С индикатором',
                                icon: <IconStacksOutline />,
                                action: () => console.log('С индикатором'),
                                hasIndicator: true
                            },
                        ]
                    },
                    {
                        items: [
                            {
                                label: 'Выход',
                                icon: <IconLogout />,
                                action: () => console.log('Выход')
                            },
                        ]
                    }
                ]}
            >
                <div style={{ padding: '20px' }}>
                    <Button onClick={() => setIsOpen(!isOpen)}>
                        Переключить меню
                    </Button>
                    <p>Основной контент приложения</p>
                </div>
            </NavigationDrawer>
        </div>
    );
}

import React, { useState } from 'react';
import { NavigationDrawer, Button } from '@salutejs/plasma-web';
import { IconBlankOutline } from '@salutejs/plasma-icons';
export function App() {
    const [isOpen, setIsOpen] = useState(false);
    return (
        <div
            style={{
                width: 500,
                height: 300,
                position: 'relative',
                overflow: 'hidden',
                transform: 'translateZ(0)',
            }}
        >
            <NavigationDrawer
                mode="overlay"
                opened={isOpen}
                onHide={() => setIsOpen(false)}
                sections={[
                    {
                        hasDivider: false,
                        items: [
                            {
                                label: 'Пункт меню',
                                action: () => console.log('Клик'),
                                icon: <IconBlankOutline />,
                            }
                        ]
                    }
                ]}
            >
                <div style={{ padding: '20px', width: '100%' }}>
                    <Button onClick={() => setIsOpen(true)}>
                        Открыть меню
                    </Button>
                    <p>Основной контент</p>
                </div>
            </NavigationDrawer>
    </div>
);
}

